196→export function PostDetailScreen({route}: Props) {
197→  const {user, session} = useAuth();
198→  const {colors} = useTheme();
199→  const {journalId} = route.params;
200→  const token = session?.access_token ?? '';
201→  const [commentInput, setCommentInput] = useState('');
202→  const [repostCaption, setRepostCaption] = useState('');
203→  const [showRepost, setShowRepost] = useState(false);
204→  const [replyingTo, setReplyingTo] = useState<{id: string; userName: string} | null>(null);
205→  const [expandedReplies, setExpandedReplies] = useState<Set<string>>(new Set());
206→  const [fetchedReplies, setFetchedReplies] = useState<Record<string, JournalComment[]>>({});
207→  const [loadingReplies, setLoadingReplies] = useState<Set<string>>(new Set());
208→  const scrollViewRef = useRef<ScrollView>(null);
209→  const inputRef = useRef<TextInput>(null);
210→
211→  const handleReply = useCallback((commentId: string, userName: string) => {
212→    setReplyingTo({id: commentId, userName});
213→    setTimeout(() => {
214→      inputRef.current?.focus();
215→      scrollViewRef.current?.scrollToEnd({animated: true});
216→    }, 100);
217→  }, []);
218→
219→  const handleToggleReplies = useCallback((commentId: string) => {
220→    setExpandedReplies(prev => {
221→      const next = new Set(prev);
222→      if (next.has(commentId)) {
223→        next.delete(commentId);
224→        return next;
225→      }
226→      next.add(commentId);
227→
228→      // Fetch replies from API if not already fetched
229→      if (!fetchedReplies[commentId]) {
230→        setLoadingReplies(p => new Set(p).add(commentId));
231→        socialApi.getReplies(journalId, commentId).then(res => {
232→          setFetchedReplies(p => ({...p, [commentId]: res.comments}));
233→          setLoadingReplies(p => {
234→            const n = new Set(p);
235→            n.delete(commentId);
236→            return n;
237→          });
238→        }).catch(() => {
239→          setLoadingReplies(p => {
240→            const n = new Set(p);
241→            n.delete(commentId);
242→            return n;
243→          });
244→        });
245→      }
246→
247→      return next;
248→    });
249→  }, [journalId, fetchedReplies]);
250→
251→  const detailQuery = useQuery({
252→    queryKey: ['journal', journalId, user?.id],
253→    queryFn: () => mobileApi.getJournalById(journalId, user?.id),
254→  });
255→
256→  const commentsQuery = useQuery({
257→    queryKey: ['journal-comments', journalId],
258→    queryFn: () => socialApi.getComments(journalId, null, 20),
259→  });
260→
261→  const reactionMutation = useMutation({
262→    mutationFn: async (reactionType: string) => {
263→      const journal = detailQuery.data?.journal;
264→      const receiverId = journal?.user_id ?? journal?.users?.id;
265→      if (!token) throw new Error('Please log in to react.');
266→      if (!journal?.id || !receiverId) throw new Error('Missing journal data.');
267→      return socialApi.toggleReaction(token, {
268→        journalId: journal.id,
269→        receiverId,
270→        reactionType,
271→      });
272→    },
273→    onSuccess: () => {
274→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
275→      queryClient.invalidateQueries({queryKey: ['feed']});
276→    },
277→    onError: e => Alert.alert('Reaction failed', e instanceof Error ? e.message : 'Error'),
278→  });
279→
280→  const bookmarkMutation = useMutation({
281→    mutationFn: async () => {
282→      if (!token) throw new Error('Please log in to bookmark.');
283→      return socialApi.toggleBookmark(token, {journalId});
284→    },
285→    onSuccess: () => {
286→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
287→      queryClient.invalidateQueries({queryKey: ['feed']});
288→    },
289→    onError: e => Alert.alert('Bookmark failed', e instanceof Error ? e.message : 'Error'),
290→  });
291→
292→  const addCommentMutation = useMutation({
293→    mutationFn: async () => {
294→      const body = commentInput.trim();
295→      const receiverId = detailQuery.data?.journal?.user_id ?? detailQuery.data?.journal?.users?.id;
296→      if (!token) throw new Error('Please log in to comment.');
297→      if (!body) throw new Error('Comment cannot be empty.');
298→      if (!receiverId) throw new Error('Missing journal owner.');
299→      return socialApi.addComment(token, {
300→        comments: body,
301→        postId: journalId,
302→        receiverId,
303→        parentId: replyingTo?.id,
304→      });
305→    },
306→    onSuccess: () => {
307→      const parentId = replyingTo?.id;
308→      setCommentInput('');
309→      setReplyingTo(null);
310→      queryClient.invalidateQueries({queryKey: ['journal-comments', journalId]});
311→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
312→      if (parentId) {
313→        // Clear cached replies so they get re-fetched with the new reply
314→        setFetchedReplies(prev => {
315→          const next = {...prev};
316→          delete next[parentId];
317→          return next;
318→        });
319→        setExpandedReplies(prev => new Set(prev).add(parentId));
320→        // Re-fetch replies for the parent
321→        setLoadingReplies(p => new Set(p).add(parentId));
322→        socialApi.getReplies(journalId, parentId).then(res => {
323→          setFetchedReplies(p => ({...p, [parentId]: res.comments}));
324→          setLoadingReplies(p => {
325→            const n = new Set(p);
326→            n.delete(parentId);
327→            return n;
328→          });
329→        }).catch(() => {
330→          setLoadingReplies(p => {
331→            const n = new Set(p);
332→            n.delete(parentId);
333→            return n;
334→          });
335→        });
336→      }
337→    },
338→    onError: e => Alert.alert('Comment failed', e instanceof Error ? e.message : 'Error'),
339→  });
340→
341→  const repostMutation = useMutation({
342→    mutationFn: async () => {
343→      if (!token) throw new Error('Please log in to repost.');
344→      return socialApi.createRepost(token, {
345→        sourceJournalId: journalId,
346→        caption: repostCaption.trim() || undefined,
347→      });
348→    },
349→    onSuccess: () => {
350→      setRepostCaption('');
351→      setShowRepost(false);
352→      Alert.alert('Reposted', 'Post was reposted to your feed.');
353→      queryClient.invalidateQueries({queryKey: ['feed']});
354→    },
355→    onError: e => Alert.alert('Repost failed', e instanceof Error ? e.message : 'Error'),
356→  });
357→
358→  const journal = detailQuery.data?.journal;
359→  const likeCount = resolveCount(journal?.like_count, journal?.likes_count);
360→  const commentCount = resolveCount(journal?.comment_count, journal?.comments_count);
361→  const bookmarkCount = resolveCount(journal?.bookmark_count);
362→  const comments = commentsQuery.data?.comments ?? [];
363→  const bannerImage = useMemo(() => extractBannerImage(journal?.content), [journal?.content]);
364→
365→  if (detailQuery.isLoading) {
366→    return (
367→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
368→        <View style={styles.loadingContainer}>
369→          <SkeletonLoader height={200} borderRadius={0} />
370→          <View style={styles.contentPadding}>
371→            <SkeletonLoader width="70%" height={24} />
372→            <SkeletonLoader width="40%" height={16} style={{marginTop: 12}} />
373→            <SkeletonLoader width="100%" height={16} style={{marginTop: 20}} />
374→            <SkeletonLoader width="100%" height={16} style={{marginTop: 8}} />
375→            <SkeletonLoader width="60%" height={16} style={{marginTop: 8}} />
376→          </View>
377→        </View>
378→      </SafeAreaView>
379→    );
380→  }
381→
382→  if (detailQuery.isError) {
383→    return (
384→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
385→        <View style={styles.contentPadding}>
386→          <Text style={[styles.errorText, {color: colors.danger}]}>
387→            Unable to load this post.
388→          </Text>
389→        </View>
390→      </SafeAreaView>
391→    );
392→  }
393→
394→  return (
395→    <ScrollView
396→      ref={scrollViewRef}
397→      style={[styles.scroll, {backgroundColor: colors.bgPrimary}]}
398→      showsVerticalScrollIndicator={false}>
399→      {/* Banner image */}
400→      {bannerImage && (
401→        <Image source={{uri: bannerImage}} style={styles.banner} resizeMode="cover" />
402→      )}
403→
404→      <View style={styles.contentPadding}>
405→        {/* Title */}
406→        <Text style={[styles.title, {color: colors.textHeading}]}>
407→          {journal?.title || 'Untitled Post'}
408→        </Text>
409→
410→        {/* Author section */}
411→        <View style={styles.authorRow}>
412→          <Avatar
413→            uri={journal?.users?.image_url}
414→            name={journal?.users?.name}
415→            size={36}
416→            badge={journal?.users?.badge as 'legend' | 'og' | undefined}
417→          />
418→          <View style={styles.authorInfo}>
419→            <View style={styles.authorNameRow}>
420→              <Text style={[styles.authorName, {color: colors.textPrimary}]}>
421→                {journal?.users?.name || 'Unknown author'}
422→              </Text>
423→              {journal?.users?.badge ? (
424→                <BadgeCheckIcon size={16} badge={journal.users.badge as 'legend' | 'og'} />
425→              ) : null}
426→            </View>
427→            <Text style={[styles.dateText, {color: colors.textMuted}]}>
428→              {formatRelativeDate(journal?.created_at)}
429→            </Text>
430→          </View>
431→        </View>
432→
433→        {/* Action bar */}
434→        <ActionBar
435→          likeCount={likeCount}
436→          commentCount={commentCount}
437→          bookmarkCount={bookmarkCount}
438→          isLiked={journal?.has_liked}
439→          isBookmarked={journal?.has_bookmarked}
440→          userReaction={journal?.user_reaction}
441→          onReact={type => reactionMutation.mutate(type)}
442→          onComment={() => {/* scroll to comments */}}
443→          onBookmark={() => bookmarkMutation.mutate()}
444→          onRepost={() => setShowRepost(!showRepost)}
445→        />
446→
447→        {/* Repost section */}
448→        {showRepost && (
449→          <View style={[styles.repostSection, {backgroundColor: colors.bgSecondary, borderColor: colors.borderLight}]}>
450→            <TextInput
451→              value={repostCaption}
452→              onChangeText={setRepostCaption}
453→              placeholder="Add an optional caption"
454→              placeholderTextColor={colors.textFaint}
455→              style={[styles.commentInput, {backgroundColor: colors.bgElevated, borderColor: colors.borderCard, color: colors.textPrimary}]}
